"use client";

import React, { useState, useMemo } from 'react';
import { 
  Sword, Shield, Zap, Search, Trophy, 
  Home, List, Users, MessageSquare, 
  ChevronRight, Settings, Crown, Target
} from 'lucide-react';
// Ensure this path is exactly where your players.json is located
import playersData from '../data/players.json';

export default function McTierFinal() {
  const [search, setSearch] = useState("");
  const [activeTab, setActiveTab] = useState("Overall");

  // useMemo with a safety check to prevent "7 errors" related to data types
  const filteredPlayers = useMemo(() => {
    const data = Array.isArray(playersData) ? playersData : [];
    return data
      .filter((player: any) => {
        const matchesSearch = player.name?.toLowerCase().includes(search.toLowerCase());
        const matchesTab = activeTab === "Overall" || player.kit === activeTab;
        return matchesSearch && matchesTab;
      })
      .sort((a: any, b: any) => (a.rank || 0) - (b.rank || 0));
  }, [search, activeTab]);

  return (
    <div className="flex min-h-screen bg-[#0d0d0f] text-[#e1e1e3] font-sans selection:bg-cyan-500/30">
      
      {/* SIDEBAR */}
      <aside className="hidden lg:flex w-20 flex-col items-center py-8 border-r border-white/5 bg-[#0a0a0c] sticky top-0 h-screen">
        <div className="mb-10 text-cyan-500 bg-cyan-500/10 p-3 rounded-2xl shadow-[0_0_20px_rgba(6,182,212,0.2)]">
          <Trophy size={28} strokeWidth={2.5} />
        </div>
        <nav className="flex flex-col gap-8 text-gray-600">
          <Home className="hover:text-white cursor-pointer transition-colors" size={24} />
          <List className="text-white cursor-pointer" size={24} />
          <Users className="hover:text-white cursor-pointer transition-colors" size={24} />
          <MessageSquare className="hover:text-white cursor-pointer transition-colors" size={24} />
          <div className="mt-auto pb-4 hover:text-white cursor-pointer"><Settings size={24} /></div>
        </nav>
      </aside>

      <div className="flex-1 flex flex-col">
        {/* HEADER */}
        <header className="h-20 border-b border-white/5 bg-[#0d0d0f]/80 backdrop-blur-xl sticky top-0 z-50 px-8 flex items-center justify-between">
          <div className="flex items-center gap-10">
            <h1 className="text-2xl font-black tracking-tighter uppercase italic flex items-center gap-2 text-white">
              MC<span className="text-cyan-500">TIERS</span>
            </h1>
          </div>

          <div className="relative w-72 md:w-96 group">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500 group-focus-within:text-cyan-400" size={16} />
            <input 
              type="text"
              placeholder="Search player..."
              className="w-full bg-[#16161a] border border-white/5 rounded-2xl py-2.5 pl-12 pr-4 outline-none focus:border-cyan-500/40 transition-all text-sm"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
          </div>
        </header>

        <main className="p-6 md:p-12 max-w-7xl mx-auto w-full">
          {/* KIT FILTER TABS */}
          <div className="flex flex-wrap gap-3 mb-10 bg-white/[0.02] p-1.5 rounded-2xl w-fit border border-white/5">
            {['Overall', 'Crystal', 'Sword', 'UHC', 'Axe', 'Pot'].map((tab) => (
              <button 
                key={tab} 
                onClick={() => setActiveTab(tab)}
                className={`px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${
                  activeTab === tab 
                  ? 'bg-cyan-500 text-white shadow-[0_10px_20px_rgba(6,182,212,0.2)]' 
                  : 'text-gray-500 hover:text-gray-200 hover:bg-white/5'
                }`}
              >
                {tab}
              </button>
            ))}
          </div>

          {/* PLAYER LIST */}
          <div className="bg-[#111114] border border-white/5 rounded-[2rem] overflow-hidden shadow-2xl">
            <div className="grid grid-cols-12 gap-4 p-6 bg-white/[0.03] border-b border-white/5 text-[10px] text-gray-600 font-black uppercase tracking-[0.25em]">
              <div className="col-span-1 pl-4">#</div>
              <div className="col-span-7 md:col-span-8">Player</div>
              <div className="col-span-4 md:col-span-3 text-right pr-8">Tier Rank</div>
            </div>

            <div className="divide-y divide-white/[0.03]">
              {filteredPlayers.length > 0 ? filteredPlayers.map((player: any) => (
                <div key={player.name} className="grid grid-cols-12 gap-4 p-5 md:p-7 items-center hover:bg-white/[0.015] transition-all group cursor-pointer relative">
                  <div className="col-span-1 text-3xl font-black italic text-gray-800/50 group-hover:text-cyan-500/30 transition-colors pl-2">
                    {player.rank}
                  </div>
                  
                  <div className="col-span-7 md:col-span-8 flex items-center gap-5">
                    <img 
                      src={`https://mc-heads.net/avatar/${player.name}/100`} 
                      className="w-14 h-14 rounded-[1.25rem] bg-[#1a1a1e] border border-white/5 group-hover:border-cyan-500/40 transition-all p-0.5"
                      alt={player.name}
                    />
                    <div>
                      <div className="flex items-center gap-2 font-black text-xl tracking-tight text-white/90 group-hover:text-white">
                         {player.name}
                         {player.rank === 1 && <Crown size={18} className="text-yellow-500 fill-yellow-500/20" />}
                      </div>
                      <div className="flex items-center gap-2 text-[10px] text-gray-500 font-black uppercase mt-1">
                        <Target size={12} className="text-cyan-500" />
                        {player.kit || 'Combat'} Specialist
                      </div>
                    </div>
                  </div>

                  <div className="col-span-4 md:col-span-3 flex justify-end items-center gap-4 pr-4">
                    <div className="bg-gradient-to-br from-[#1a1a1e] to-[#0d0d0f] border border-white/10 px-6 py-2.5 rounded-2xl shadow-xl group-hover:border-cyan-500/50 transition-all">
                      <span className={`text-2xl font-black italic tracking-tighter ${player.tier?.includes('H') ? 'text-cyan-400' : 'text-white'}`}>
                        {player.tier}
                      </span>
                    </div>
                    <ChevronRight size={24} className="text-gray-800 group-hover:text-cyan-500/40 transition-all" />
                  </div>
                </div>
              )) : (
                <div className="p-40 text-center opacity-10 font-black text-4xl uppercase italic">No Players Found</div>
              )}
            </div>
          </div>
        </main>
      </div>
    </div>
  );
}